import{_ as a,o as i,c as r,ag as s}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Paneles de distribución","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/equipment/distribution-panels.md","filePath":"es/power-systems/equipment/distribution-panels.md"}'),n={name:"es/power-systems/equipment/distribution-panels.md"};function o(l,e,t,c,d,p){return i(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="paneles-de-distribucion" tabindex="-1">Paneles de distribución <a class="header-anchor" href="#paneles-de-distribucion" aria-label="Permalink to &quot;Paneles de distribución&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los paneles de distribución son gabinetes que dividen la energía eléctrica en circuitos derivados más pequeños a baja tensión.</p><p>Reciben energía del equipo aguas arriba y la distribuyen a cargas finales como iluminación, contactos, motores pequeños y sistemas de control.</p><p>Los paneles de distribución típicamente se ubican cerca de las áreas que sirven para reducir la longitud del cableado y mejorar la organización del sistema.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de los paneles de distribución es:</p><ul><li>Distribuir energía a circuitos y cargas individuales</li><li>Proporcionar protección y aislamiento localizados</li><li>Simplificar el cableado y reducir la complejidad del enrutamiento</li><li>Permitir acceso seguro para operación y mantenimiento</li></ul><p>Representan la etapa final de distribución de energía antes de que la energía llegue al equipo de uso final.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>La energía se suministra al panel de distribución a través de un alimentador desde un tablero de distribución o una fuente similar.</p><p>Dentro del panel:</p><ul><li>Las barras colectoras distribuyen energía a través del panel</li><li>Los interruptores automáticos protegen los circuitos derivados individuales</li><li>Cada circuito de salida alimenta una carga específica o un grupo de cargas</li></ul><p>Cuando ocurre una falla en un circuito derivado, el interruptor automático correspondiente se dispara, aislando solo ese circuito.</p><p>Esto evita que las fallas afecten otras cargas conectadas al mismo panel.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los paneles de distribución se utilizan en:</p><ul><li>Circuitos de iluminación y contactos</li><li>Cargas de motores pequeños y equipo auxiliar</li><li>Tableros de control y sistemas de automatización</li><li>Servicios de edificios comerciales e industriales</li><li>Distribución local en áreas de producción</li></ul><p>Se instalan en toda la instalación para acercar la energía al punto de uso.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Número de circuitos</strong><br> Debe soportar las cargas actuales y permitir capacidad de reserva para expansión</p></li><li><p><strong>Capacidad de corriente</strong><br> El panel y las barras colectoras deben manejar la demanda total de carga</p></li><li><p><strong>Selección de interruptores automáticos</strong><br> Las capacidades adecuadas aseguran protección y coordinación con los dispositivos aguas arriba</p></li><li><p><strong>Capacidad de cortocircuito</strong><br> Debe coincidir con la corriente de falla disponible en el punto de instalación</p></li><li><p><strong>Ubicación</strong><br> Debe minimizar la longitud del cableado y permitir acceso seguro</p></li><li><p><strong>Condiciones ambientales</strong><br> El tipo de gabinete debe coincidir con las condiciones de polvo, humedad y temperatura</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los paneles sobrecargados son un problema común en instalaciones en expansión</li><li>El etiquetado deficiente dificulta el diagnóstico y el mantenimiento</li><li>Mantener espacio de reserva para interruptores automáticos reduce el esfuerzo de instalación futura</li><li>El apriete adecuado de terminales previene sobrecalentamiento y fallas</li><li>Los paneles deben instalarse a alturas accesibles para una operación segura</li></ul>',23)])])}const b=a(n,[["render",o]]);export{m as __pageData,b as default};
